// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// STRY0081901 - When the top Template Task is deleted, delete the Template
	var grProcessTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
	if(grProcessTemplate.get(current.getValue('tasker_process_definition'))){
		var deleteMsg = '[' + grProcessTemplate.getValue('number') + ':' + grProcessTemplate.getValue('template_name') + ']' + gs.getMessage('Tasker - Top Template Task was deleted, Deleting Template');
		grProcessTemplate.deleteRecord();
		gs.info(deleteMsg);
	}	

})(current, previous);
